@js:
// 5. 详情页跳转逻辑（原版逻辑保持不变）
if (!baseUrl.includes("hksexdoll.com")) {
    // 只要不是娃娃官网，直接跳浏览器
    java.startBrowser(baseUrl, "正在前往...");
    result = "正在跳转到外部浏览器播放...<br>" + baseUrl;
} else {
    // 娃娃详情页解析（原版代码不动）
    var doc = org.jsoup.Jsoup.parse(result);
    var myImgs = [];
    var rawList = doc.select(".brxe-image-gallery img, .bricks-image-gallery img, noscript img, .entry-content img");
    for (var i = 0; i < rawList.size(); i++) {
        var s = rawList.get(i).attr("data-src") || rawList.get(i).attr("src");
        if (s && s.startsWith("http") && !s.toLowerCase().includes(".svg") && !s.includes("100x100") && !myImgs.includes(s)) {
            myImgs.push(s);
        }
    }
    var displayTitle = (typeof title !== 'undefined' && title && title !== "null") ? title : (doc.select("h1").text() || "1:1 Show");
    var h = "<!DOCTYPE html><html><head><style>body{margin:0;background:#000;color:#eee;font-family:sans-serif;padding-bottom:50px} .top{background:#1a1a1a;color:#888;text-align:center;padding:12px;font-size:11px;position:sticky;top:0;z-index:99;letter-spacing:2px;border-bottom:1px solid #222} .header{padding:35px 20px 20px;background:#000;text-align:center} .img-wrap{padding:0 8px} .img-item{position:relative;margin-bottom:10px;border-radius:2px;overflow:hidden} .img-item img{width:100%;display:block;background:#111} .img-count{position:absolute;bottom:8px;right:10px;background:rgba(0,0,0,0.4);color:#999;padding:2px 6px;border-radius:2px;font-size:10px;font-family:monospace}</style></head><body>";
    h += "<div class='top'>HD VISUAL SHOWCASE</div>";
    h += "<div class='header'><h1 style='font-size:19px;margin:0;font-weight:400;color:#fff;letter-spacing:0.5px'>" + displayTitle + "</h1></div>";
    h += "<div class='img-wrap'>";
    for(var k=0; k<myImgs.length; k++){
        h += "<div class='img-item'><img src='" + myImgs[k] + "'><span class='img-count'>" + (k+1) + " / " + myImgs.length + "</span></div>";
    }
    h += "</div><p style='text-align:center;color:#222;font-size:9px;margin-top:30px;letter-spacing:1px'>EXHIBITION ONLY</p></body></html>";
    result = h;
}
result;

